```python
import csv
import json

def _normalize_row(row):
    name = row['name'].strip().title()
    email = row['email'].strip().lower()
    age = int(row['age'])
    return name, email, age

def _filter_and_collect(rows):
    results = []
    for row in rows:
        name, email, age = _normalize_row(row)
        if age >= 18 and '@' in email:
            results.append({'name': name, 'email': email, 'age': age})
    return results

def process_csv(path):
    with open(path) as f:
        reader = csv.DictReader(f)
        return _filter_and_collect(reader)

def process_json(path):
    with open(path) as f:
        data = json.load(f)
        return _filter_and_collect(data)
```

